<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
                <div role="document" class="modal-dialog" style="max-width: 1300px !important;">
                    <div class="modal-content">
                        <div
                            class="modal-header mheader-user">
                            <button type="button" class="close" @click="CloseRuleTemplateModel">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                            <h4 class="modal-title">
                                {{ $t('AddBillingRuleFromTemplate') }} 
                            </h4>
                            
                            <span class="user-guide">
                                <a class="ancuserguide text-white" data-toggle="collapse" href="javascript:;" role="button" aria-expanded="false" aria-controls="collapseExample">
                                    <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}
                                </a>
                                <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                    <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                        <div class="con"  v-html="getUserGuideTitle()"></div>
                                    </div>
                                </div>
                            </span>
                        </div>

                        <div class="modal-body">
                            <dynamic-form lang="en" ref="validateTemplate" :buttons="buttons" :schema="FormSchema"
                                :mandatorytext="$t('MandatoryString')">
                                 <template v-slot:tgslot-BillingRuleTemplate="{ data }">
                                    <div id="divconversationbox">
                                        <div class="listing">
                                            <div id="accordion" class="w-100">
                                                <div v-for="(group, index) in billingTemplateListing" :key="group.pricingMethodId">
                                                    <div class="card mb-4">
                                                        <div class="card-header">
                                                            <a data-toggle="collapse" :href="'#collapse'+index" aria-expanded="true" style="color: #000 !important;">
                                                                <div class="conversation-date heading-border">
                                                                    <span>
                                                                        <b>{{ group.pricingMethod }}</b>
                                                                    </span>
                                                                </div>
                                                            </a>
                                                        </div>

                                                        <div :id="'collapse'+index" :class="['collapse', index === 0 ? 'show' : '']">
                                                            <div class="card-body">
                                                                <div class="user_type_choice mt-2 coloredicons">
                                                                    <div v-for="item in group.items" :key="item.configurationId" class="btn-group btn-group-toggle custom-reports-icons my-2" :title="item.billingTemplateName">
                                                                        <label class="btn btn_cstm lblconfigurationid" :class="{ active: selectedConfigurationId === item.configurationId }">
                                                                                <input type="radio" name="rdoconfiguration" :id="'lblconfigurationid_' + item.configurationId" :value="item.configurationId" v-model="selectedConfigurationId" />
                                                                                <span class="d-block pb-2">
                                                                                    <i class="fa fa-folder-open-o bg-transparent"></i>
                                                                                </span>
                                                                                {{ item.billingTemplateName }}
                                                                        </label>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </template>
                            </dynamic-form>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>
<script>
import DataService from "../../services/DataService";
import {
    locateBillingService
} from "../../services/locateBillingService";
export default {
    props: {
        callbackfunction: {
            type: Function
        }
    },
    data() {
        return {
            isLoading: false,
            isShown:false,
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('RuleName'),
                            name: 'RuleName',
                            palceholder: this.$t('RuleName'),
                            value: "",
                            validationRules: {
                                required: true
                            },
                            disabled: false,
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('Client Name'),
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('SearchAndSelectClient'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange
                            },
                            validationRules: {
                                "required": true
                            },
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('IsRuleApllicableToAll'),
                            name: "allutilities",
                            visibility: true,
                            disabled: false,
                            value: "",
                            config: {
                                options: [{ value: "1", name: this.$t('Yes') }, { value: "0", name: this.$t('No') }],
                                onChange: this.onChangeApplicable
                            }

                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: { selectAll: true,  clear: true },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": true
                            },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('EffectiveFromDate')+' '+'(M/D/YYYY)',
                            name: "Effectivefrom",
                            value: new Date().toLocaleDateString(),
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                // minDate: new Date(),
                                // onChange: this.setTimerDate,
                                maxDate: false
                            },
                            validationRules: { "required": true },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('EffectiveToDate')+' '+'(M/D/YYYY)',
                            name: "Effectiveto",
                            value: new Date('12/31/2099').toLocaleDateString(),
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                minDate: new Date(),
                                onChange: this.setTimerDate,
                                maxDate: false
                            },
                            validationRules: { "required": true },
                        }
                    ],

                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "SlotField",
                            label: this.$t('BillingRuleTemplate'),
                            name: "BillingRuleTemplate",
                            value: "",
                            visibility: true,
                            placeholder: "",
                            config: {
                                options: [],
                            },
                            validationRules: { "required": false, max: 365 },
                             settings: {
                                isInSlot: true
                            }
                        },
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save'),
                    onClick: this.SaveBillingRuleTemplate
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.CloseRuleTemplateModel,
                },
            ],
            billingTemplateListing: [],
            selectedConfigurationId: null,
            clientList:[]
            
        }
    },
    created: async function () {
        var vm = this;
        vm.GetDDLCompanyContractClients();
    },
    mounted() {
        this.GetBillingTemplateListGroupByPricingMethod();
         this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;
            }, 50);
        });
    },
    methods: {
        onChangeApplicable() {
            debugger;
            var utilityselectval = this.$refs.validateTemplate.getPropertyValue("allutilities", "value");
            switch (utilityselectval) {
                case true:
                    this.$refs.validateTemplate.updateProperty("UtilityName", "visibility", false);
                    this.$refs.validateTemplate.updateProperty("UtilityName", "validationRules.required", false);
                    this.$refs.validateTemplate.updateProperty("UtilityName", "value", "");
                    break;
                default:
                    this.$refs.validateTemplate.updateProperty("UtilityName", "visibility", true);
                    this.$refs.validateTemplate.updateProperty("UtilityName", "validationRules.required", true);
            }

        },
        getUserGuideTitle() {
            let text = this.$t('User_Guide_Add_Billing_Rule_From_Template');
            return text
                .replace(/\\n/g, '')
                .replace(/\\t/g, '&nbsp;');
        },
        
        GetBillingTemplateListGroupByPricingMethod() {
            DataService.GetBillingTemplateListGroupByPricingMethod()
                .then(response => {
                    const templateListing = response.data;
                    // Group by pricingMethodId
                    const grouped = templateListing.reduce((acc, item) => {

                        if (!acc[item.pricingMethodId]) {
                            acc[item.pricingMethodId] = {
                                pricingMethodId: item.pricingMethodId,
                                pricingMethod: item.pricingMethod,
                                items: []
                            };
                        }

                        acc[item.pricingMethodId].items.push(item);

                        return acc;

                    }, {});

                    // IMPORTANT: assign new array reference
                    this.billingTemplateListing = Object.values(grouped);

                })
                .catch(error => {
                    console.error(error);
                });
        },

        GetDDLCompanyContractClients: async function () {
            var vm = this;
            const url = `pageNum=&pageSize=&reqFrom=CUSTOM&search=&userId=&screenName=BILLINGRULE`;
            DataService.GetAvailableContracts(url).then((response) => {
                try {
                    if (response?.data?.result) {
                        vm.clientList = JSON.parse(response?.data?.result || "null");
                        var items = (vm.clientList || []).map(function (x) {
                            return {
                                text: x.CHILD_NAME,
                                value: x.CHILD_USER_ID,
                                groupText: x.PARENT_NAME,
                                groupValue: x.PARENT_ID,
                                displayValue: x.CHILD_NAME,
                                status: null
                            };
                        });
                        vm.$refs.validateTemplate.updateProperty("ContractName", "config.options", items);
                        vm.$refs.validateTemplate.UpdateKeyValue();
                    } else {
                        vm.clientList = [];
                        vm.$refs.validateTemplate.updateProperty("ContractName", "config.options", vm.clientList);
                        vm.$refs.validateTemplate.UpdateKeyValue();
                        
                    }
                } catch (e) {
                    console.error("Error parsing contract result:", e);
                }
            })
        },
        onSelectionChange: async function(value, x) {
            var vm = this;
            vm.isLoading = true;
            vm.selectedClientId = x;
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;
            await locateBillingService.getUtilityList(url).then(response => {
                vm.isLoading = false;
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                     vm.$refs.validateTemplate.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                     vm.$refs.validateTemplate.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        CloseRuleTemplateModel() {
            var vm = this;
            vm.$nextTick(() => {
                setTimeout(() => {
                    vm.isShown =false;
                    }, 50);
            });
            vm.$refs.validateTemplate.updateProperty("RuleName", "value", "");
            vm.$refs.validateTemplate.updateProperty("ContractName", "value", "");
            this.$parent.isModalBillingRuleTemplate =false;
            vm.callbackfunction();
        },
        SaveBillingRuleTemplate: async function () {
            var vm = this;
            const isValid = await vm.$refs.validateTemplate.validateForm.validate();
            if (!isValid) {
                this.isLoading = false;
                return;
            }
            var utilityValues = vm.$refs.validateTemplate.getPropertyValue("UtilityName", "value");
            var selectUtility = Array.isArray(utilityValues) ? utilityValues.join(",") : utilityValues;
            var postString = {
                "configurationId": vm.selectedConfigurationId,
                "ServiceId": 0,
                "RuleName": vm.$refs.validateTemplate.getPropertyValue("RuleName", "value"),
                "ClientId": vm.$refs.validateTemplate.getPropertyValue("ContractName", "value"),
                "IsRuleApllicableToAll": vm.$refs.validateTemplate.getPropertyValue("allutilities", "value"),
                "SelectDivision": selectUtility,
                "CompanyId": 0,
                "CompanyName": "",
                "EffectiveFromDate": vm.$refs.validateTemplate.getPropertyValue("Effectivefrom", "value"),
                "EffectiveToDate": vm.$refs.validateTemplate.getPropertyValue("Effectiveto", "value"),
            };
            await DataService.SaveBillingRuleFromTemplate(postString).then((response) => {
                if (response.data != '') {
                    if (Number(response.data.status) == 0) {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Rules')]), "Success", true, vm.$t('Alert'));
                        vm.cloneItem = [];
                        vm.CloseRuleTemplateModel();
                    }
                    else if(Number(response.data.status) == 2){
                          vm.ShowAlert(vm.$t("RuleNameAlreadyExists"), "warning", true);
                    }
                    else if(Number(response.data.status) == -11){
                        vm.ShowAlert(vm.$t("RuleNameAlreadyExistsForClient"), "warning", true);
                    }
                    else if(Number(response.data.status) == -22){
                        vm.ShowAlert(vm.$t("RuleNameAlreadyExistsForChildClient"), "warning", true);
                    }
                    else {
                        vm.ShowAlert(vm.$t('AddedError', [vm.$t('Rules')]), "danger", true, vm.$t('Alert'));
                    }
                }
            })

        }
    },
    
}

</script>
